<?php
namespace App\Console\Commands;
use App\Models\Document;use App\Models\Procurement\VendorDocument;use Illuminate\Console\Command;
class MigrateVendorDocuments extends Command{protected $signature='documents:migrate-vendor-documents';protected $description='Migrate vendor_documents into documents';public function handle(){ $m=$s=$f=0; VendorDocument::withTrashed()->chunkById(100,function($rows) use (&$m,&$s,&$f){foreach($rows as $r){try{$exists=Document::where('owner_type','vendor')->where('owner_id',$r->vendor_id)->where('metadata->legacy_source','vendor_documents')->where('metadata->legacy_id',$r->id)->exists(); if($exists){$s++;continue;} Document::create(['owner_type'=>'vendor','owner_id'=>$r->vendor_id,'document_type_id'=>$r->document_type_id,'title'=>$r->document_type ?? ('Document '.$r->id),'file_path'=>$r->file_path ?? 'legacy/missing','original_file_name'=>$r->original_filename,'mime_type'=>$r->mime_type,'file_size'=>$r->file_size,'document_number'=>$r->document_number,'issue_date'=>$r->issue_date,'expiry_date'=>$r->expiry_date,'status'=>$r->verification_status==='valid'?'verified':'uploaded','metadata'=>['legacy_source'=>'vendor_documents','legacy_id'=>$r->id]]);$m++;}catch(\Throwable $e){$f++;}}}); $this->info("migrated=$m skipped=$s failed=$f"); return self::SUCCESS;}}
